import MadeThemeProvider from '../components/theme-provider/src/theme-provider.component.js';
function buildAndRegister(name, colorMode, properties) {
    const declarations = Object.entries(properties)
        .map(([key, value]) => `${key}: ${value};`)
        .join(' ');
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(`:host { ${declarations} }`);
    MadeThemeProvider.registerTheme(name, colorMode, sheet);
}
/**
 * Creates and registers a custom theme for use with `<made-theme-provider>`.
 *
 * Provide a `modes` object with `light` and/or `dark` keys to register one
 * or both colour modes in a single call.
 *
 * Use `basedOn` to extend a built-in theme — all of the base theme's tokens
 * are inherited and only the values you supply in `modes` are overridden.
 *
 * Use `fonts` to inject `@font-face` declarations into the document. The
 * string is injected once per theme name, regardless of how many times
 * `createTheme` is called.
 *
 * @example
 * ```ts
 * import { createTheme } from '@mc-made/web-components/themes';
 *
 * const myTheme = createTheme({
 *   name: 'my-brand',
 *   basedOn: 'mastercard',
 *   fonts: `
 *     @font-face {
 *       font-family: 'MyFont';
 *       font-weight: 400;
 *       src: url('/fonts/MyFont-Regular.woff2') format('woff2');
 *     }
 *   `,
 *   modes: {
 *     light: { '--made-color-brand-primary': '#0070f3' },
 *     dark:  { '--made-color-brand-primary': '#3399ff' },
 *   }
 * });
 *
 * // myTheme === 'my-brand'
 * // <made-theme-provider theme=${myTheme}></made-theme-provider>
 * ```
 */
export function createTheme(options) {
    for (const [colorMode, properties] of Object.entries(options.modes)) {
        if (properties) {
            buildAndRegister(options.name, colorMode, properties);
        }
    }
    if (options.basedOn) {
        MadeThemeProvider.setThemeBase(options.name, options.basedOn);
    }
    if (options.fonts) {
        MadeThemeProvider.injectFonts(options.name, options.fonts);
    }
    return options.name;
}
